        let u = Int(edge[0])
        let v = Int(edge[1])
        let s = Int(edge[2])
        let must = Int(edge[3])
        if must == 1 {
            must_edges.append((u: u, v: v, s: s))
        } else {
            non_must_edges.append((u: u, v: v, s: s))
        }
    }

    var low: Int = 1
    var high: Int = 200000
    var ans: Int64 = -1

