        var parent = Array(0..<n)
        var rank = Array(repeating:0, count:n)
        var comp = n
        var upgrades_used = 0

        func find(_ x: Int) -> Int {
            var node = x
            while parent[node] != node {
                node = parent[node]
            }
            let root = node
            var current = x
            while parent[current] != root {
                let next = parent[current]
                parent[current] = root
                current = next
            }
            return root
