                parent[rv] = ru
            } else {
                parent[rv] = ru
                rank[ru] += 1
            }
            comp -= 1
        }

        var setB = [(u: Int, v: Int, s: Int)]()
        for edge in non_must_edges {
            let u = edge.u
            let v = edge.v
            let s = edge.s
            if s >= x {
