                if rank[ru] < rank[rv] {
                    parent[ru] = rv
                } else if rank[ru] > rank[rv] {
                    parent[rv] = ru
                } else {
                    parent[rv] = ru
                    rank[ru] += 1
                }
                comp -= 1
            } else if 2 * s >= x {
                setB.append(edge)
            }
        }

        for edge in setB {
            if comp == 1 {
                break
            }
            if upgrades_used >= k {
                break
            }
            let u = edge.u
            let v = edge.v
            let s = edge.s
            let ru = find(u)
            let rv = find(v)
