                    parent[ru] = rv
                } else if rank[ru] > rank[rv] {
                    parent[rv] = ru
                } else {
                    parent[rv] = ru
                    rank[ru] += 1
                }
                comp -= 1
                upgrades_used += 1
            }
        }

        return comp == 1
    }

    while low <= high {
        let mid = (low + high) / 2
        if check(n: n_int, must_edges: must_edges, non_must_edges: non_must_edges, k: k_int, x: mid) {
            ans = Int64(mid)
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    return ans
}
