struct DSU {
    std::vector<int64_t> parent;
    std::vector<int64_t> rank;

    DSU(int64_t n) {
        parent.resize(n);
        rank.resize(n, 0);
        for (int64_t i = 0; i < n; ++i) {
            parent[i] = i;
        }
    }

    int64_t find(int64_t x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    bool union_set(int64_t x, int64_t y) {
        int64_t rx = find(x);
        int64_t ry = find(y);
        if (rx == ry) {
            return false;
        }
        if (rank[rx] < rank[ry]) {
            std::swap(rx, ry);
        }
        parent[ry] = rx;
        if (rank[rx] == rank[ry]) {
            rank[rx] += 1;
        }
        return true;
    }
};

