        if (edge[2] > max_s) {
            max_s = edge[2];
        }
    }
    int64_t high = max_s * 2;
    int64_t low = 1;
    int64_t ans = -1;

    auto check = [n, must_edges, optional_edges, k](int64_t mid) -> bool {
        DSU dsu(n);
        int64_t comp = n;

        for (const auto& edge : must_edges) {
